SELECT ?mountain ?mountainLabel ?ascent ?date WHERE {
  ?ascent wdt:P31 wd:Q1194369 ; wdt:P585 ?date .
  FILTER ( ?date >= "1945-01-01T00:00:00Z" ^^ xsd:dateTime ) ?mountain wdt:P793 ?ascent ; wdt:P31 wd:Q8502 .
  OPTIONAL {
    ?mountain rdfs:label ?mountainLabel FILTER ( LANG( ?mountainLabel ) = "en" )
  }
}
ORDER BY ?date
LIMIT 200

