PREFIX p: <http://www.wikidata.org/prop/>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?person ?personLabel ?net WHERE {
  {
    SELECT ( MAX( ?net ) AS ?maxNet ) WHERE {
      ?p wdt:P31 wd:Q5 ; wdt:P21 wd:Q6581072 ; p:P2218 ?st .
      ?st ps:P2218 ?net .
    }
  }
  ?person wdt:P31 wd:Q5 ; wdt:P21 wd:Q6581072 ; p:P2218 ?netWorthStatement .
  ?netWorthStatement ps:P2218 ?net .
  FILTER ( ?net = ?maxNet ) OPTIONAL {
    ?person rdfs:label ?personLabel FILTER ( lang( ?personLabel ) = "en" )
  }
}

