PREFIX pq: <http://www.wikidata.org/prop/qualifier/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX p: <http://www.wikidata.org/prop/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX ps: <http://www.wikidata.org/prop/statement/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?country ?countryLabel ( GROUP_CONCAT( DISTINCT ?capLabel ; separator = ", " ) AS ?capitals ) ( COUNT( DISTINCT ?cap ) AS ?nCaps ) WHERE {
  ?country wdt:P31 wd:Q3624078 .
  FILTER NOT EXISTS {
    ?country wdt:P31 wd:Q3024240
  }
  .
  FILTER NOT EXISTS {
    ?country wdt:P576 ?dissolved
  }
  .
  ?country p:P36 ?st .
  ?st ps:P36 ?cap .
  FILTER NOT EXISTS {
    ?st pq:P582 ?end .
  }
  OPTIONAL {
    ?country rdfs:label ?countryLabel FILTER ( LANG( ?countryLabel ) = "en" )
  }
  OPTIONAL {
    ?cap rdfs:label ?capLabel FILTER ( LANG( ?capLabel ) = "en" )
  }
}
GROUP BY ?country ?countryLabel
HAVING ( COUNT( DISTINCT ?cap ) > 1 )
ORDER BY ?countryLabel

