      SELECT DISTINCT ?diedInOfficePerson WHERE {
        ?stmt ps:P39 wd:Q30461 ; pq:P580 ?start .
        OPTIONAL {
          ?stmt pq:P582 ?end .
        }
        ?diedInOfficePerson wdt:P570 ?death ; p:P39 ?stmt .
        FILTER ( ( BOUND( ?end ) && ?death >= ?start && ?death <= ?end ) || ( ! BOUND( ?end ) && ?death >= ?start ) )
      }
    }
  }
}

